var surah023 = {
  number: 23,
  nameArabic: "al-Mu'minun",
  nameEnglish: "Al-Mu'minun",
  meaning: "The Believers",
  totalAyahs: 118,
  ayahs: [
    { number: 1, arabic: "قَدْ أَفْلَحَ ٱلْمُؤْمِنُونَ", transliteration: "Qad aflaha almuminoona", transliterationB: "Qad aflahal mu'minoon", english: "The believers must (eventually) win through", romanUrdu: "Yaqeenan falaah payi hai iman laney walon ne jo" },
    { number: 2, arabic: "ٱلَّذِينَ هُمْ فِى صَلَاتِهِمْ خَٰشِعُونَ", transliteration: "Allatheena hum fee salatihim khashiAAoona", transliterationB: "Allazeena hum fee Salaatihim khaashi'oon", english: "Those who humble themselves in their prayers", romanUrdu: "Apni namaz mein khushu ikhtiyar karte hain (Salat with humility)" },
    { number: 3, arabic: "وَٱلَّذِينَ هُمْ عَنِ ٱللَّغْوِ مُعْرِضُونَ", transliteration: "Waallatheena hum AAani allaghwi muAAridoona", transliterationB: "Wallazeena hum 'anillaghwimu'ridoon", english: "Who avoid vain talk", romanUrdu: "Laghviyat (vain things) se door rehte hain" },
    { number: 4, arabic: "وَٱلَّذِينَ هُمْ لِلزَّكَوٰةِ فَٰعِلُونَ", transliteration: "Waallatheena hum lilzzakati faAAiloona", transliterationB: "Wallazeena hum liz Zakaati faa'iloon", english: "Who are active in deeds of charity", romanUrdu: "Zakaat ke tareeqe par aamil hotey hain" },
    { number: 5, arabic: "وَٱلَّذِينَ هُمْ لِفُرُوجِهِمْ حَٰفِظُونَ", transliteration: "Waallatheena hum lifuroojihim hafithoona", transliterationB: "Wallazeena hum lifuroo jihim haafizoon", english: "Who abstain from sex", romanUrdu: "Apni sharmgaahon ki hifazat karte hain" },
    { number: 6, arabic: "إِلَّا عَلَىٰٓ أَزْوَٰجِهِمْ أَوْ مَا مَلَكَتْ أَيْمَٰنُهُمْ فَإِنَّهُمْ غَيْرُ مَلُومِينَ", transliteration: "Illa AAala azwajihim aw ma malakat aymanuhum fainnahum ghayru maloomeena", transliterationB: "Illaa 'alaaa azwaajihim aw maa malakat aimaanuhum fa innahum ghairu maloomeen", english: "Except with those joined to them in the marriage bond, or (the captives) whom their right hands possess,- for (in their case) they are free from blame", romanUrdu: "Siwaye apni biwiyon ke aur un auraton ke jo unki milk e yameen mein hon (right hand posseses) ke unpar (mehfooz na rakhne mein) woh qabil e malamat nahin hain" },
    { number: 7, arabic: "فَمَنِ ٱبْتَغَىٰ وَرَآءَ ذَٰلِكَ فَأُو۟لَٰٓئِكَ هُمُ ٱلْعَادُونَ", transliteration: "Famani ibtagha waraa thalika faolaika humu alAAadoona", transliterationB: "Famanib taghaa waraaa'a zaalika fa ulaaa'ika humul 'aadoon", english: "But those whose desires exceed those limits are transgressors", romanUrdu: "Albatta jo uske alawa kuch aur chahein wahi zyadati karne waley hain" },
    { number: 8, arabic: "وَٱلَّذِينَ هُمْ لِأَمَٰنَٰتِهِمْ وَعَهْدِهِمْ رَٰعُونَ", transliteration: "Waallatheena hum liamanatihim waAAahdihim raAAoona", transliterationB: "Wallazeena hum li amaanaatihim wa 'ahdihim raa'oon", english: "Those who faithfully observe their trusts and their covenants", romanUrdu: "Apni amanaton (trusts) aur apne ahad o paiman (promises) ka paas rakhte hain" },
    { number: 9, arabic: "وَٱلَّذِينَ هُمْ عَلَىٰ صَلَوَٰتِهِمْ يُحَافِظُونَ", transliteration: "Waallatheena hum AAala salawatihim yuhafithoona", transliterationB: "Wallazeena hum 'alaa Salawaatihim yuhaafizoon", english: "And who (strictly) guard their prayers", romanUrdu: "Aur apni namazon ki muhafizat (hifazat) karte hain" },
    { number: 10, arabic: "أُو۟لَٰٓئِكَ هُمُ ٱلْوَٰرِثُونَ", transliteration: "Olaika humu alwarithoona", transliterationB: "Ulaaa'ika humul waarisoon", english: "These will be the heirs", romanUrdu: "Yahi log woh waris hain" },
    { number: 11, arabic: "ٱلَّذِينَ يَرِثُونَ ٱلْفِرْدَوْسَ هُمْ فِيهَا خَٰلِدُونَ", transliteration: "Allatheena yarithoona alfirdawsa hum feeha khalidoona", transliterationB: "Allazeena yarisoonal Firdawsa hum feehaa khaalidoon", english: "Who will inherit Paradise: they will dwell therein (for ever)", romanUrdu: "Jo miraas mein firdous payenge aur usmein hamesha rahenge" },
    { number: 12, arabic: "وَلَقَدْ خَلَقْنَا ٱلْإِنسَٰنَ مِن سُلَٰلَةٍۢ مِّن طِينٍۢ", transliteration: "Walaqad khalaqna alinsana min sulalatin min teenin", transliterationB: "Wa laqad khalaqnal insaana min sulaalatim minteen", english: "Man We did create from a quintessence (of clay)", romanUrdu: "Humne Insaan ko mitti ke saatt (essence of clay) se banaya" },
    { number: 13, arabic: "ثُمَّ جَعَلْنَٰهُ نُطْفَةًۭ فِى قَرَارٍۢ مَّكِينٍۢ", transliteration: "Thumma jaAAalnahu nutfatan fee qararin makeenin", transliterationB: "Summa ja'alnaahu nutfatan fee qaraarim makeen", english: "Then We placed him as (a drop of) sperm in a place of rest, firmly fixed", romanUrdu: "Phir usey ek mehfooz jaga tapki hui boondh mein tabdeel kiya" },
    { number: 14, arabic: "ثُمَّ خَلَقْنَا ٱلنُّطْفَةَ عَلَقَةًۭ فَخَلَقْنَا ٱلْعَلَقَةَ مُضْغَةًۭ فَخَلَقْنَا ٱلْمُضْغَةَ عِظَٰمًۭا فَكَسَوْنَا ٱلْعِظَٰمَ لَحْمًۭا ثُمَّ أَنشَأْنَٰهُ خَلْقًا ءَاخَرَ ۚ فَتَبَارَكَ ٱللَّهُ أَحْسَنُ ٱلْخَٰلِقِينَ", transliteration: "Thumma khalaqna alnnutfata AAalaqatan fakhalaqna alAAalaqata mudghatan fakhalaqna almudghata AAithaman fakasawna alAAithama lahman thumma anshanahu khalqan akhara fatabaraka Allahu ahsanu alkhaliqeena", transliterationB: "Summa khalaqnan nutfata 'alaqatan fakhalaqnal 'alaqata mudghatan fakhalaq nal mudghata 'izaaman fakasawnal 'izaama lahman summa anshaanaahu khalqan aakhar; fatabaarakal laahu ahsanul khaaliqeen", english: "Then We made the sperm into a clot of congealed blood; then of that clot We made a (foetus) lump; then we made out of that lump bones and clothed the bones with flesh; then we developed out of it another creature. So blessed be Allah, the best to create", romanUrdu: "Phir us boondh ko lothday ki shakal di, phir lothday ko boti bana diya, phir boti ki haddiyan (bones) banayin, phir haddiyon par gosht chadhaya. Phir usey ek dusri hi makhlooq bana khada kiya. Pas bada hi ba-barakat hai Allah, sab karigaron se accha kaarigar(creator)" },
    { number: 15, arabic: "ثُمَّ إِنَّكُم بَعْدَ ذَٰلِكَ لَمَيِّتُونَ", transliteration: "Thumma innakum baAAda thalika lamayyitoona", transliterationB: "Summa innakum ba'da zaalika la maaiyitoon", english: "After that, at length ye will die", romanUrdu: "Phir iske baad tumko zaroor marna hai" },
    { number: 16, arabic: "ثُمَّ إِنَّكُمْ يَوْمَ ٱلْقِيَٰمَةِ تُبْعَثُونَ", transliteration: "Thumma innakum yawma alqiyamati tubAAathoona", transliterationB: "Summa innakum Yawmal Qiyaamati tub'asoon", english: "Again, on the Day of Judgment, will ye be raised up", romanUrdu: "Phir qayamat ke roz yaqeenan tum uthaye jaogey" },
    { number: 17, arabic: "وَلَقَدْ خَلَقْنَا فَوْقَكُمْ سَبْعَ طَرَآئِقَ وَمَا كُنَّا عَنِ ٱلْخَلْقِ غَٰفِلِينَ", transliteration: "Walaqad khalaqna fawqakum sabAAa taraiqa wama kunna AAani alkhalqi ghafileena", transliterationB: "Wa laqad khalaqnaa fawqakum sab'a taraaa'iqa wa maa kunnaa 'anil khalqi ghaafileen", english: "And We have made, above you, seven tracts; and We are never unmindful of (our) Creation", romanUrdu: "Aur tumhare upar humne saat (seven) raastey banaye, takhleeq ke kaam se hum kuch na-balad na thay (We are never unmindful of (our) Creation" },
    { number: 18, arabic: "وَأَنزَلْنَا مِنَ ٱلسَّمَآءِ مَآءًۢ بِقَدَرٍۢ فَأَسْكَنَّٰهُ فِى ٱلْأَرْضِ ۖ وَإِنَّا عَلَىٰ ذَهَابٍۭ بِهِۦ لَقَٰدِرُونَ", transliteration: "Waanzalna mina alssamai maan biqadarin faaskannahu fee alardi wainna AAala thahabin bihi laqadiroona", transliterationB: "Wa anzalnaa minas samaaa'i maaa'am biqadarin fa-askannaahu fil ardi wa innaa 'alaa zahaabim bihee laqaa diroon", english: "And We send down water from the sky according to (due) measure, and We cause it to soak in the soil; and We certainly are able to drain it off (with ease)", romanUrdu: "Aur aasmaan se humne theek hisaab ke mutabiq ek khaas miqdar mein pani utara aur usko zameen mein thehara diya. Hum usey jis tarah chahein gayab kar sakte hain" },
    { number: 19, arabic: "فَأَنشَأْنَا لَكُم بِهِۦ جَنَّٰتٍۢ مِّن نَّخِيلٍۢ وَأَعْنَٰبٍۢ لَّكُمْ فِيهَا فَوَٰكِهُ كَثِيرَةٌۭ وَمِنْهَا تَأْكُلُونَ", transliteration: "Faanshana lakum bihi jannatin min nakheelin waaAAnabin lakum feeha fawakihu katheeratun waminha takuloona", transliterationB: "Fa anshaanaa lakum bihee Jannaatim min nakheelinw wa a'naab; lakum feehaa fawaakihu kaseeratunw wa minhaa taakuloon", english: "With it We grow for you gardens of date-palms and vines: in them have ye abundant fruits: and of them ye eat (and have enjoyment)", romanUrdu: "Phir is pani ke zariye se humne tumhare liye khajoor aur angoor ke baagh paida kardiye, tumhare liye in baaghon mein bahut se lazeez phal hain aur unsey tum rozi haasil karte ho" },
    { number: 20, arabic: "وَشَجَرَةًۭ تَخْرُجُ مِن طُورِ سَيْنَآءَ تَنۢبُتُ بِٱلدُّهْنِ وَصِبْغٍۢ لِّلْءَاكِلِينَ", transliteration: "Washajaratan takhruju min toori saynaa tanbutu bialdduhni wasibghin lilakileena", transliterationB: "Wa shajaratan takhruju min Toori Sainaaa'a tambutu bidduhni wa sibghil lil aakileen", english: "Also a tree springing out of Mount Sinai, which produces oil, and relish for those who use it for food", romanUrdu: "Aur woh darakht bhi humne paida kiya jo Tur-e-seena (mount sinai) se nikalta hai, teil (oil) bhi liye huey ugta hai aur khane walon ke liye saalan bhi" },
    { number: 21, arabic: "وَإِنَّ لَكُمْ فِى ٱلْأَنْعَٰمِ لَعِبْرَةًۭ ۖ نُّسْقِيكُم مِّمَّا فِى بُطُونِهَا وَلَكُمْ فِيهَا مَنَٰفِعُ كَثِيرَةٌۭ وَمِنْهَا تَأْكُلُونَ", transliteration: "Wainna lakum fee alanAAami laAAibratan nusqeekum mimma fee butooniha walakum feeha manafiAAu katheeratun waminha takuloona", transliterationB: "Wa inna lakum fil an'aami la'ibrah; nusqeekum mimmaa fee butoonihaa wa lakum feehaa manaafi'u kaseeratunw wa minhaa taakuloon", english: "And in cattle (too) ye have an instructive example: from within their bodies We produce (milk) for you to drink; there are, in them, (besides), numerous (other) benefits for you; and of their (meat) ye eat", romanUrdu: "Aur haqeeqat yeh hai ke tumhare liye maweshiyon mein bhi ek sabaq hai unke paithon (bellies) mein jo kuch hai usi mein se ek cheez hum tumhein pilatey hain, aur tumhare liye unmein bahut se dusre faiyde bhi hain" },
    { number: 22, arabic: "وَعَلَيْهَا وَعَلَى ٱلْفُلْكِ تُحْمَلُونَ", transliteration: "WaAAalayha waAAala alfulki tuhmaloona", transliterationB: "Wa 'alaihaa wa'alal fulki tuhmaloon", english: "And on them, as well as in ships, ye ride", romanUrdu: "Unko tum khate ho aur unpar aur kashtiyon par sawaar bhi kiye jatey ho" },
    { number: 23, arabic: "وَلَقَدْ أَرْسَلْنَا نُوحًا إِلَىٰ قَوْمِهِۦ فَقَالَ يَٰقَوْمِ ٱعْبُدُوا۟ ٱللَّهَ مَا لَكُم مِّنْ إِلَٰهٍ غَيْرُهُۥٓ ۖ أَفَلَا تَتَّقُونَ", transliteration: "Walaqad arsalna noohan ila qawmihi faqala ya qawmi oAAbudoo Allaha ma lakum min ilahin ghayruhu afala tattaqoona", transliterationB: "Wa laqad arsalnaa Noohan ilaa qawmihee faqaala yaa qawmi'budul laaha maa lakum min ilahin ghairuhoo afalaa tattaqoon", english: "(Further, We sent a long line of prophets for your instruction). We sent Noah to his people: He said, \"O my people! worship Allah! Ye have no other god but Him. Will ye not fear (Him)", romanUrdu: "Humne Nooh ko uski qaum ki taraf bheja, usne kaha “ aey meri qaum ke logon, Allah ki bandagi karo, uske siwa tumhare liye koi aur mabood nahin hai, kya tum darte nahin ho?”" },
    { number: 24, arabic: "فَقَالَ ٱلْمَلَؤُا۟ ٱلَّذِينَ كَفَرُوا۟ مِن قَوْمِهِۦ مَا هَٰذَآ إِلَّا بَشَرٌۭ مِّثْلُكُمْ يُرِيدُ أَن يَتَفَضَّلَ عَلَيْكُمْ وَلَوْ شَآءَ ٱللَّهُ لَأَنزَلَ مَلَٰٓئِكَةًۭ مَّا سَمِعْنَا بِهَٰذَا فِىٓ ءَابَآئِنَا ٱلْأَوَّلِينَ", transliteration: "Faqala almalao allatheena kafaroo min qawmihi ma hatha illa basharun mithlukum yureedu an yatafaddala AAalaykum walaw shaa Allahu laanzala malaikatan ma samiAAna bihatha fee abaina alawwaleena", transliterationB: "Faqaalal mala'ul lazeena kafaroo min qawmihee maa haazaaa illaa basharum mislukum yureedu ai yatafaddala 'alaikum wa law shaaa'al laahu la anzala malaaa'ikatam maa sami'naa bihaazaa feee aabaaa'inal awwaleen", english: "The chiefs of the Unbelievers among his people said: \"He is no more than a man like yourselves: his wish is to assert his superiority over you: if Allah had wished (to send messengers), He could have sent down angels; never did we hear such a thing (as he says), among our ancestors of old", romanUrdu: "Uski qaum ke jin sardaaron ne maanne se inkar kiya woh kehne lagey ke “yeh shaks kuch nahin hai magar ek bashar(Insaan) tum hi jaisa. Iski garz yeh hai ke tumpar bartari (superiority) haasil karey. Allah ko agar bhejna hota to farishtey bhejta.Yeh baat to humne kabhi apne baap dada ke waqton mein suni hi nahin ( ke bashar Rasool bankar aaye)" },
    { number: 25, arabic: "إِنْ هُوَ إِلَّا رَجُلٌۢ بِهِۦ جِنَّةٌۭ فَتَرَبَّصُوا۟ بِهِۦ حَتَّىٰ حِينٍۢ", transliteration: "In huwa illa rajulun bihi jinnatun fatarabbasoo bihi hatta heenin", transliterationB: "In huwa illaa rajulum bihee jinnatun fatarabbasoo bihee hattan heen", english: "(And some said): \"He is only a man possessed: wait (and have patience) with him for a time", romanUrdu: "Kuch nahin , bas is aadmi ko zara junoon lahaq(possessed) ho gaya hai, kuch muddat aur dekhlo [ ( shayad ifaqa ho jaaye)( may be he is cured)]”" },
    { number: 26, arabic: "قَالَ رَبِّ ٱنصُرْنِى بِمَا كَذَّبُونِ", transliteration: "Qala rabbi onsurnee bima kaththabooni", transliterationB: "Qaala Rabbin surnee bimaa kazzaboon", english: "(Noah) said: \"O my Lord! help me: for that they accuse me of falsehood", romanUrdu: "Nooh ne kaha “parwardigar, in logon ne jo meri takzeeb ki hai ispar ab tu hi meri nusrat farma.”" },
    { number: 27, arabic: "فَأَوْحَيْنَآ إِلَيْهِ أَنِ ٱصْنَعِ ٱلْفُلْكَ بِأَعْيُنِنَا وَوَحْيِنَا فَإِذَا جَآءَ أَمْرُنَا وَفَارَ ٱلتَّنُّورُ ۙ فَٱسْلُكْ فِيهَا مِن كُلٍّۢ زَوْجَيْنِ ٱثْنَيْنِ وَأَهْلَكَ إِلَّا مَن سَبَقَ عَلَيْهِ ٱلْقَوْلُ مِنْهُمْ ۖ وَلَا تُخَٰطِبْنِى فِى ٱلَّذِينَ ظَلَمُوٓا۟ ۖ إِنَّهُم مُّغْرَقُونَ", transliteration: "Faawhayna ilayhi ani isnaAAi alfulka biaAAyunina wawahyina faitha jaa amruna wafara alttannooru faosluk feeha min kullin zawjayni ithnayni waahlaka illa man sabaqa AAalayhi alqawlu minhum wala tukhatibnee fee allatheena thalamoo innahum mughraqoona", transliterationB: "Fa awhainaaa ilaihi anis na'il fulka bi a'yuninaa wa wahyinaa fa izaa jaaa'a amrunaa wa faarat tannooru fasluk feehaa min kullin zawjainis naini wa ahlaka illaa man sabaqa 'alaihil qawlu minhum wa laa tukhaat ibnee fil lazeena zalamooo innaahum mughraqoon", english: "So We inspired him (with this message): \"Construct the Ark within Our sight and under Our guidance: then when comes Our Command, and the fountains of the earth gush forth, take thou on board pairs of every species, male and female, and thy family- except those of them against whom the Word has already gone forth: And address Me not in favour of the wrong-doers; for they shall be drowned (in the Flood)", romanUrdu: "Humne uspar wahee ki ke “hamari nigrani mein aur hamari wahee ke mutabiq kashti (ark) tayyar kar. Phir jab hamara hukum aa jaye aur tannur ubal paday to har qisam ke jaanwaron mein se ek ek joda lekar usmein sawaar ho ja, aur apne ehal o ayaal ko bhi saath le, siwai unke jinke khilaf pehle faisla ho chuka hai, aur zaalimon ke maamle mein mujhse kuch na kehna, yeh ab garq (doob/ drown) honay waley hain" },
    { number: 28, arabic: "فَإِذَا ٱسْتَوَيْتَ أَنتَ وَمَن مَّعَكَ عَلَى ٱلْفُلْكِ فَقُلِ ٱلْحَمْدُ لِلَّهِ ٱلَّذِى نَجَّىٰنَا مِنَ ٱلْقَوْمِ ٱلظَّٰلِمِينَ", transliteration: "Faitha istawayta anta waman maAAaka AAala alfulki faquli alhamdu lillahi allathee najjana mina alqawmi alththalimeena", transliterationB: "Fa izas tawaita ata wa mam ma'aka 'alal fulki faqulil hamdu lillaahil lazee najjaanaa minal qawmiz zalimeen", english: "And when thou hast embarked on the Ark - thou and those with thee,- say: \"Praise be to Allah, Who has saved us from the people who do wrong", romanUrdu: "Phir jab tu apne saathiyon sameth kashti par sawar ho jaye to keh, shukar hai us khuda ka jisne humein zaalim logon se nijaat di" },
    { number: 29, arabic: "وَقُل رَّبِّ أَنزِلْنِى مُنزَلًۭا مُّبَارَكًۭا وَأَنتَ خَيْرُ ٱلْمُنزِلِينَ", transliteration: "Waqul rabbi anzilnee munzalan mubarakan waanta khayru almunzileena", transliterationB: "Wa qur Rabbi anzilnee munzalam mubaarakanw wa Anta khairul munzileen", english: "And say: \"O my Lord! enable me to disembark with thy blessing: for Thou art the Best to enable (us) to disembark", romanUrdu: "Aur keh, parwardigar, mujhko barakat wali jagah utaar aur tu behtareen jagah dene wala hai.”" },
    { number: 30, arabic: "إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ وَإِن كُنَّا لَمُبْتَلِينَ", transliteration: "Inna fee thalika laayatin wain kunna lamubtaleena", transliterationB: "Inna fee zaalika la Aayaatinw wa in kunnaa lamubtaleen", english: "Verily in this there are Signs (for men to understand); (thus) do We try (men)", romanUrdu: "Is qissey mein badi nishaniyan hain aur aazmaish to hum karke hi rehte hain" },
    { number: 31, arabic: "ثُمَّ أَنشَأْنَا مِنۢ بَعْدِهِمْ قَرْنًا ءَاخَرِينَ", transliteration: "Thumma anshana min baAAdihim qarnan akhareena", transliterationB: "Summaa anshaana mim ba'dihim qarnan aakhareen", english: "Then We raised after them another generation", romanUrdu: "Inke baad humne ek dusre daur ki qaum uthayi" },
    { number: 32, arabic: "فَأَرْسَلْنَا فِيهِمْ رَسُولًۭا مِّنْهُمْ أَنِ ٱعْبُدُوا۟ ٱللَّهَ مَا لَكُم مِّنْ إِلَٰهٍ غَيْرُهُۥٓ ۖ أَفَلَا تَتَّقُونَ", transliteration: "Faarsalna feehim rasoolan minhum ani oAAbudoo Allaha ma lakum min ilahin ghayruhu afala tattaqoona", transliterationB: "Fa arsalnaa feehim Rasoolam minhum ani'budul laaha maa lakum min ilaahin ghairuhoo afalaa tattaqoon", english: "And We sent to them a messenger from among themselves, (saying), \"Worship Allah! ye have no other god but Him. Will ye not fear (Him)", romanUrdu: "Phir un mein khud unhi ki qaum ka ek Rasool bheja ( jisne unhein dawat di) ke Allah ki bandagi karo, tumhare liye uske siwa koi aur maabood nahin hai, kya tum darte nahin ho" },
    { number: 33, arabic: "وَقَالَ ٱلْمَلَأُ مِن قَوْمِهِ ٱلَّذِينَ كَفَرُوا۟ وَكَذَّبُوا۟ بِلِقَآءِ ٱلْءَاخِرَةِ وَأَتْرَفْنَٰهُمْ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا مَا هَٰذَآ إِلَّا بَشَرٌۭ مِّثْلُكُمْ يَأْكُلُ مِمَّا تَأْكُلُونَ مِنْهُ وَيَشْرَبُ مِمَّا تَشْرَبُونَ", transliteration: "Waqala almalao min qawmihi allatheena kafaroo wakaththaboo biliqai alakhirati waatrafnahum fee alhayati alddunya ma hatha illa basharun mithlukum yakulu mimma takuloona minhu wayashrabu mimma tashraboona", transliterationB: "Wa qaalal mala-u min qawmihil lazeena kafaroo wa kazzaboo bi liqaaa'il Aakhirati wa atrafnaahum fil hayaatid dunyaa maa haazaaa illaa basharum mislukum yaakulu mimmaa taakuloona minhu wa yashrabu mimmaa tashraboon", english: "And the chiefs of his people, who disbelieved and denied the Meeting in the Hereafter, and on whom We had bestowed the good things of this life, said: \"He is no more than a man like yourselves: he eats of that of which ye eat, and drinks of what ye drink", romanUrdu: "Uski qaum ke jin sardaron ne maanne se inkar kiya aur aakhirat ki peshi ko jhutlaya, jinko humne duniya ki zindagi mein aasuda kar rakkha tha, woh kehne lagey “ye shaks kuch nahin hai magar ek bashar tum hi jaisa, jo kuch tum khate ho wahi yeh khata hai aur jo kuch tum peete ho wahi yeh peeta hai" },
    { number: 34, arabic: "وَلَئِنْ أَطَعْتُم بَشَرًۭا مِّثْلَكُمْ إِنَّكُمْ إِذًۭا لَّخَٰسِرُونَ", transliteration: "Walain ataAAtum basharan mithlakum innakum ithan lakhasiroona", transliterationB: "Wa la'in at'atum basharam mislakum innakum izal lakhaasiroon", english: "If ye obey a man like yourselves, behold, it is certain ye will be lost", romanUrdu: "Ab agar tumne apne hi jaise ek bashar ki itaat qabool karli to tum ghatay hi mein rahey" },
    { number: 35, arabic: "أَيَعِدُكُمْ أَنَّكُمْ إِذَا مِتُّمْ وَكُنتُمْ تُرَابًۭا وَعِظَٰمًا أَنَّكُم مُّخْرَجُونَ", transliteration: "AyaAAidukum annakum itha mittum wakuntum turaban waAAithaman annakum mukhrajoona", transliterationB: "A-Ya'idukum annakum izaa mittum wa kuntum turaabanw wa izaaman annakum mukhrajoon", english: "Does he promise that when ye die and become dust and bones, ye shall be brought forth (again)", romanUrdu: "Yeh tumhein ittila deta hai ke jab tum mar kar mitti ho jaogey aur haddiyon ka panjar reh jaogey us waqt tum (qabaron se) nikale jaogey" },
    { number: 36, arabic: "۞ هَيْهَاتَ هَيْهَاتَ لِمَا تُوعَدُونَ", transliteration: "Hayhata hayhata lima tooAAadoona", transliterationB: "Haihaata haihaata limaa too'adoon", english: "Far, very far is that which ye are promised", romanUrdu: "Baeed (far/Impossible), bilkul baeed(Impossible) hai yeh wada jo tumse kiya jaa raha hai" },
    { number: 37, arabic: "إِنْ هِىَ إِلَّا حَيَاتُنَا ٱلدُّنْيَا نَمُوتُ وَنَحْيَا وَمَا نَحْنُ بِمَبْعُوثِينَ", transliteration: "In hiya illa hayatuna alddunya namootu wanahya wama nahnu bimabAAootheena", transliterationB: "In hiya illaa hayaatunad dunyaa namootu wa nahyaa wa maa nahnu bimab'ooseen", english: "There is nothing but our life in this world! We shall die and we live! But we shall never be raised up again", romanUrdu: "Zindagi kuch nahin hai magar bas yahi duniya ki zindagi. Yahin humko marna aur jeena hai aur hum hargiz uthaye janey waley nahin hain" },
    { number: 38, arabic: "إِنْ هُوَ إِلَّا رَجُلٌ ٱفْتَرَىٰ عَلَى ٱللَّهِ كَذِبًۭا وَمَا نَحْنُ لَهُۥ بِمُؤْمِنِينَ", transliteration: "In huwa illa rajulun iftara AAala Allahi kathiban wama nahnu lahu bimumineena", transliterationB: "In huwa illaa rajulunif taraa 'alal laahi kazibanw wa maa nahnuu lahoo bimu'mineen", english: "He is only a man who invents a lie against Allah, but we are not the ones to believe in him", romanUrdu: "Yeh shaks khuda ke naam par mehaz jhoot ghadh raha hai aur hum kabhi iske maanne waley nahin hain.”" },
    { number: 39, arabic: "قَالَ رَبِّ ٱنصُرْنِى بِمَا كَذَّبُونِ", transliteration: "Qala rabbi onsurnee bima kaththabooni", transliterationB: "Qaala Rabbin surnee bimaa kazzaboon", english: "(The prophet) said: \"O my Lord! help me: for that they accuse me of falsehood", romanUrdu: "Rasool ne kaha “parwardigar , in logon ne jo meri takzeeb ki hai, ispar ab tu hi meri nusrat farma”" },
    { number: 40, arabic: "قَالَ عَمَّا قَلِيلٍۢ لَّيُصْبِحُنَّ نَٰدِمِينَ", transliteration: "Qala AAamma qaleelin layusbihunna nadimeena", transliterationB: "Qaala 'ammaa qaleelil la yusbihunna naadimeen", english: "(Allah) said: \"In but a little while, they are sure to be sorry", romanUrdu: "Jawab mein irshad hua “qareeb hai woh waqt jab yeh apne kiye par pachtayenge”" },
    { number: 41, arabic: "فَأَخَذَتْهُمُ ٱلصَّيْحَةُ بِٱلْحَقِّ فَجَعَلْنَٰهُمْ غُثَآءًۭ ۚ فَبُعْدًۭا لِّلْقَوْمِ ٱلظَّٰلِمِينَ", transliteration: "Faakhathathumu alssayhatu bialhaqqi fajaAAalnahum ghuthaan fabuAAdan lilqawmi alththalimeena", transliterationB: "Fa akhazat humus saihatu bilhaqqi faja'alnaahum ghusaaa'aa; fabu;dal lilqaw miz zaalimeen", english: "Then the Blast overtook them with justice, and We made them as rubbish of dead leaves (floating on the stream of Time)! So away with the people who do wrong", romanUrdu: "Aakhir e kaar theek theek haqq ke mutabiq ek hungama e azeem ne unko aa liya aur humne inko kachra bana kar phenk diya. Door ho zaalim qaum" },
    { number: 42, arabic: "ثُمَّ أَنشَأْنَا مِنۢ بَعْدِهِمْ قُرُونًا ءَاخَرِينَ", transliteration: "Thumma anshana min baAAdihim quroonan akhareena", transliterationB: "Summa anshaanaa mim ba'dihim quroonan aakhareen", english: "Then We raised after them other generations", romanUrdu: "Phir humne unke baad dusri qaumein uthayi" },
    { number: 43, arabic: "مَا تَسْبِقُ مِنْ أُمَّةٍ أَجَلَهَا وَمَا يَسْتَـْٔخِرُونَ", transliteration: "Ma tasbiqu min ommatin ajalaha wama yastakhiroona", transliterationB: "Maa tasbiqu min ummatin ajalahaa wa maa yastaakhiroon", english: "No people can hasten their term, nor can they delay (it)", romanUrdu: "Koi qaum na apne waqt se pehle khatam hui aur na uske baad thehar saki" },
    { number: 44, arabic: "ثُمَّ أَرْسَلْنَا رُسُلَنَا تَتْرَا ۖ كُلَّ مَا جَآءَ أُمَّةًۭ رَّسُولُهَا كَذَّبُوهُ ۚ فَأَتْبَعْنَا بَعْضَهُم بَعْضًۭا وَجَعَلْنَٰهُمْ أَحَادِيثَ ۚ فَبُعْدًۭا لِّقَوْمٍۢ لَّا يُؤْمِنُونَ", transliteration: "Thumma arsalna rusulana tatra kulla ma jaa ommatan rasooluha kaththaboohu faatbaAAna baAAdahum baAAdan wajaAAalnahum ahadeetha fabuAAdan liqawmin la yuminoona", transliterationB: "Summa arsalnaa Rusulanaa tatraa kulla maa jaaa'a ummatar Rasooluhaa kazzabooh; fa atba'naa ba'dahum ba'danw wa ja'alnaahum ahaadees; fabu'dal liqawmil laa yu'minoon", english: "Then sent We our messengers in succession: every time there came to a people their messenger, they accused him of falsehood: so We made them follow each other (in punishment): We made them as a tale (that is told): So away with a people that will not believe", romanUrdu: "Phir humne pai dar pai apne Rasool bheje. Jis qaum ke paas bhi uska Rasool aaya, usne usey jhutlaya, aur hum ek ke baad ek qaum ko halaak karte chale gaye hatta ke unko bas afsana hi bana kar choda, phitkar un logon par jo iman nahin laatey" },
    { number: 45, arabic: "ثُمَّ أَرْسَلْنَا مُوسَىٰ وَأَخَاهُ هَٰرُونَ بِـَٔايَٰتِنَا وَسُلْطَٰنٍۢ مُّبِينٍ", transliteration: "Thumma arsalna moosa waakhahu haroona biayatina wasultanin mubeenin", transliterationB: "Summa arsalnaa Moosaa wa akhaahu Haaroona bi Aayaatinaa wa sultaanim mubeen", english: "Then We sent Moses and his brother Aaron, with Our Signs and authority manifest", romanUrdu: "Phir humne Moosa aur uske bhai Haroon ko apni nishaniyon aur khuli sanad ke saath Firoun aur uske ayaan sultanat ki taraf bheja" },
    { number: 46, arabic: "إِلَىٰ فِرْعَوْنَ وَمَلَإِي۟هِۦ فَٱسْتَكْبَرُوا۟ وَكَانُوا۟ قَوْمًا عَالِينَ", transliteration: "Ila firAAawna wamalaihi faistakbaroo wakanoo qawman AAaleena", transliterationB: "Ilaa Fir'awna wa mala'ihee fastakbaroo wa kaanoo qawman 'aaleem", english: "To Pharaoh and his Chiefs: But these behaved insolently: they were an arrogant people", romanUrdu: "Magar unhon ne takabbur (arrogance) kiya aur badi dunki li" },
    { number: 47, arabic: "فَقَالُوٓا۟ أَنُؤْمِنُ لِبَشَرَيْنِ مِثْلِنَا وَقَوْمُهُمَا لَنَا عَٰبِدُونَ", transliteration: "Faqaloo anuminu libasharayni mithlina waqawmuhuma lana AAabidoona", transliterationB: "Faqaaloo annu'minu libasharaini mislinaa wa qawmuhumaa lanaa 'aabidoon", english: "They said: \"Shall we believe in two men like ourselves? And their people are subject to us", romanUrdu: "Kehne lage “Kya hum apne hi jaise do aadmiyon par iman le aayein? Aur aadmi bhi woh jinki qaum hamari bandi (ghulam) hai”" },
    { number: 48, arabic: "فَكَذَّبُوهُمَا فَكَانُوا۟ مِنَ ٱلْمُهْلَكِينَ", transliteration: "Fakaththaboohuma fakanoo mina almuhlakeena", transliterationB: "Fakazzaboohumaa fakaanoo minal mmuhlakeen", english: "So they accused them of falsehood, and they became of those who were destroyed", romanUrdu: "Pas unhon ne dono ko jhutla diya aur halaak honay walon mein jaa miley" },
    { number: 49, arabic: "وَلَقَدْ ءَاتَيْنَا مُوسَى ٱلْكِتَٰبَ لَعَلَّهُمْ يَهْتَدُونَ", transliteration: "Walaqad atayna moosa alkitaba laAAallahum yahtadoona", transliterationB: "Wa laqad aatainaa Moosal Kitaaba la'allahum yahtadoon", english: "And We gave Moses the Book, in order that they might receive guidance", romanUrdu: "Aur Moosa ko humne kitaab ata farmayi taa-ke log ussey rehnumayi haasil karein" },
    { number: 50, arabic: "وَجَعَلْنَا ٱبْنَ مَرْيَمَ وَأُمَّهُۥٓ ءَايَةًۭ وَءَاوَيْنَٰهُمَآ إِلَىٰ رَبْوَةٍۢ ذَاتِ قَرَارٍۢ وَمَعِينٍۢ", transliteration: "WajaAAalna ibna maryama waommahu ayatan waawaynahuma ila rabwatin thati qararin wamaAAeenin", transliterationB: "Wa ja'alnab na Maryama wa ummahooo aayatannw wa aawainaahumaaa ilaa rabwatin zaati qaraarinw wa ma'een", english: "And We made the son of Mary and his mother as a Sign: We gave them both shelter on high ground, affording rest and security and furnished with springs", romanUrdu: "Aur Ibne Maryam aur uski maa ko humne ek nishani banaya aur unko ek sateh murtafa (shelter on a plateau) par rakkha jo itminaan ki jagah thi aur chashme usmein jaari thay" },
    { number: 51, arabic: "يَٰٓأَيُّهَا ٱلرُّسُلُ كُلُوا۟ مِنَ ٱلطَّيِّبَٰتِ وَٱعْمَلُوا۟ صَٰلِحًا ۖ إِنِّى بِمَا تَعْمَلُونَ عَلِيمٌۭ", transliteration: "Ya ayyuha alrrusulu kuloo mina alttayyibati waiAAmaloo salihan innee bima taAAmaloona AAaleemun", transliterationB: "Yaaa aiyuhar Rusulu kuloo minat taiyibaati wa'maloo saalihan innee bimaa ta'maloona 'Aleem", english: "O ye messengers! enjoy (all) things good and pure, and work righteousness: for I am well-acquainted with (all) that ye do", romanUrdu: "Aey paigambaron, khao paak cheezein aur amal karo saleh, tum jo kuch bhi karte ho, main usko khoob jaanta hoon" },
    { number: 52, arabic: "وَإِنَّ هَٰذِهِۦٓ أُمَّتُكُمْ أُمَّةًۭ وَٰحِدَةًۭ وَأَنَا۠ رَبُّكُمْ فَٱتَّقُونِ", transliteration: "Wainna hathihi ommatukum ommatan wahidatan waana rabbukum faittaqooni", transliterationB: "Wa inna haaziheee ummatukum ummatanw waahidatanw wa Ana Rabbukum fattaqoon", english: "And verily this Brotherhood of yours is a single Brotherhood, and I am your Lord and Cherisher: therefore fear Me (and no other)", romanUrdu: "Aur yeh tumhari yeh ummat ek hi ummat hai aur main tumhara Rubb hoon, pas mujhi se tum daro" },
    { number: 53, arabic: "فَتَقَطَّعُوٓا۟ أَمْرَهُم بَيْنَهُمْ زُبُرًۭا ۖ كُلُّ حِزْبٍۭ بِمَا لَدَيْهِمْ فَرِحُونَ", transliteration: "FataqattaAAoo amrahum baynahum zuburan kullu hizbin bima ladayhim farihoona", transliterationB: "Fataqatta'ooo amrahum bainahum zuburaa; kullu hizbim bimaa ladaihim farihoon", english: "But people have cut off their affair (of unity), between them, into sects: each party rejoices in that which is with itself", romanUrdu: "Magar baad mein logon ne apne deen (religion) ko aapas mein tukde tukde karliya, har giroh ke paas jo kuch hai usi mein woh magan hai" },
    { number: 54, arabic: "فَذَرْهُمْ فِى غَمْرَتِهِمْ حَتَّىٰ حِينٍ", transliteration: "Fatharhum fee ghamratihim hatta heenin", transliterationB: "Fazarhum fee ghamratihim hattaa heen", english: "But leave them in their confused ignorance for a time", romanUrdu: "Accha, to chodo inhein, doobey rahein apni gaflat mein ek waqt e khaas tak" },
    { number: 55, arabic: "أَيَحْسَبُونَ أَنَّمَا نُمِدُّهُم بِهِۦ مِن مَّالٍۢ وَبَنِينَ", transliteration: "Ayahsaboona annama numidduhum bihi min malin wabaneena", transliterationB: "A-yahsaboona annnamaa numiduhum bihee mimmaalinw wa baneen", english: "Do they think that because We have granted them abundance of wealth and sons", romanUrdu: "Kya yeh samajhte hain ke hum jo inhein maal o aulad se madad diye jaa rahey hain" },
    { number: 56, arabic: "نُسَارِعُ لَهُمْ فِى ٱلْخَيْرَٰتِ ۚ بَل لَّا يَشْعُرُونَ", transliteration: "NusariAAu lahum fee alkhayrati bal la yashAAuroona", transliterationB: "Nusaari'u lahum fil khairaat; bal laa yash'uroon", english: "We would hasten them on in every good? Nay, they do not understand", romanUrdu: "To goya inhein bhalaiyan dene mein sargarm hain? Nahin, asal maamle ka inhein shaour nahin hai" },
    { number: 57, arabic: "إِنَّ ٱلَّذِينَ هُم مِّنْ خَشْيَةِ رَبِّهِم مُّشْفِقُونَ", transliteration: "Inna allatheena hum min khashyati rabbihim mushfiqoona", transliterationB: "Innal lazeena hum min khashyati Rabbihim mushfiqoon", english: "Verily those who live in awe for fear of their Lord", romanUrdu: "Jo apne Rubb ke khauf se darey rehte hain" },
    { number: 58, arabic: "وَٱلَّذِينَ هُم بِـَٔايَٰتِ رَبِّهِمْ يُؤْمِنُونَ", transliteration: "Waallatheena hum biayati rabbihim yuminoona", transliterationB: "Wallazeena hum bi Aayaati Rabbihim yu'minoon", english: "Those who believe in the Signs of their Lord", romanUrdu: "Jo Rubb ki aayat par iman latey hain" },
    { number: 59, arabic: "وَٱلَّذِينَ هُم بِرَبِّهِمْ لَا يُشْرِكُونَ", transliteration: "Waallatheena hum birabbihim la yushrikoona", transliterationB: "Wallazeena hum bi Rabbihim laa yushrikoon", english: "Those who join not (in worship) partners with their Lord", romanUrdu: "Jo apne Rubb ke saath kisi ko shareek nahin karte" },
    { number: 60, arabic: "وَٱلَّذِينَ يُؤْتُونَ مَآ ءَاتَوا۟ وَّقُلُوبُهُمْ وَجِلَةٌ أَنَّهُمْ إِلَىٰ رَبِّهِمْ رَٰجِعُونَ", transliteration: "Waallatheena yutoona ma ataw waquloobuhum wajilatun annahum ila rabbihim rajiAAoona", transliterationB: "Wallazeena yu'toona maaa aataw wa quloobuhum wajilatun annahum ilaa Rabbihim raaji'oon", english: "And those who dispense their charity with their hearts full of fear, because they will return to their Lord", romanUrdu: "Aur jinka haal yeh hai ke detay hain jo kuch bhi detay hain aur dil unke is khayal se kaampte rehte hain ke humein apne Rubb ki taraf palatna hai" },
    { number: 61, arabic: "أُو۟لَٰٓئِكَ يُسَٰرِعُونَ فِى ٱلْخَيْرَٰتِ وَهُمْ لَهَا سَٰبِقُونَ", transliteration: "Olaika yusariAAoona fee alkhayrati wahum laha sabiqoona", transliterationB: "Ulaaa'ika yusaari'oona fil khairaati wa hum lahaa saabiqoon", english: "It is these who hasten in every good work, and these who are foremost in them", romanUrdu: "Bhalaiyon ki taraf daudne waley aur sabaqat karke unhein paa lene waley to dar-haqeeqat woh log hain" },
    { number: 62, arabic: "وَلَا نُكَلِّفُ نَفْسًا إِلَّا وُسْعَهَا ۖ وَلَدَيْنَا كِتَٰبٌۭ يَنطِقُ بِٱلْحَقِّ ۚ وَهُمْ لَا يُظْلَمُونَ", transliteration: "Wala nukallifu nafsan illa wusAAaha waladayna kitabun yantiqu bialhaqqi wahum la yuthlamoona", transliterationB: "Wa laa nukallifu nafsan illaa wus'ahaa wa ladainaa kitaabuny yantiqu bilhaqqi w ahum la yuzlamoon", english: "On no soul do We place a burden greater than it can bear: before Us is a record which clearly shows the truth: they will never be wronged", romanUrdu: "Hum kisi shaks ko uski maqdart (taaqat) se zyada ki takleef nahin detay aur humare paas ek kitaab hai jo (har ek ka haal) theek theek bata dene wali hai, aur logon par zulm bahr-haal nahin kiya jayega" },
    { number: 63, arabic: "بَلْ قُلُوبُهُمْ فِى غَمْرَةٍۢ مِّنْ هَٰذَا وَلَهُمْ أَعْمَٰلٌۭ مِّن دُونِ ذَٰلِكَ هُمْ لَهَا عَٰمِلُونَ", transliteration: "Bal quloobuhum fee ghamratin min hatha walahum aAAmalun min dooni thalika hum laha AAamiloona", transliterationB: "Bal quloobuhum fee ghamratim min haazaa wa lahum a'maalum min dooni zaalika hum lahaa 'aamiloon", english: "But their hearts are in confused ignorance of this; and there are, besides that, deeds of theirs, which they will (continue) to do", romanUrdu: "Magar yeh log is maamle se be-khabar hain aur inke aamal bhi is tareeqe se ( jiska upar zikr kiya gaya hai) mukhtalif hain. Woh apne yeh karoot kiye chale jayenge" },
    { number: 64, arabic: "حَتَّىٰٓ إِذَآ أَخَذْنَا مُتْرَفِيهِم بِٱلْعَذَابِ إِذَا هُمْ يَجْـَٔرُونَ", transliteration: "Hatta itha akhathna mutrafeehim bialAAathabi itha hum yajaroona", transliterationB: "Hattaaa izaaa akhznaa mutrafeehim bil'azaabi izaa hum yaj'aroon", english: "Until, when We seize in Punishment those of them who received the good things of this world, behold, they will groan in supplication", romanUrdu: "Yahan tak ke jab hum unke ayyashon (affluent ones /aasuda haal) ko azaab mein pakad lenge to phir woh dakrana shuru kar denge (begin to bellow /cry)" },
    { number: 65, arabic: "لَا تَجْـَٔرُوا۟ ٱلْيَوْمَ ۖ إِنَّكُم مِّنَّا لَا تُنصَرُونَ", transliteration: "La tajaroo alyawma innakum minna la tunsaroona", transliterationB: "Laa taj'arul yawma innakum minnaa laa tunsaroon", english: "(It will be said): \"Groan not in supplication this day: for ye shall certainly not be helped by Us", romanUrdu: "Ab bandh karo apni fariyad o fugaan, hamari taraf se ab koi madad tumhein nahin milni" },
    { number: 66, arabic: "قَدْ كَانَتْ ءَايَٰتِى تُتْلَىٰ عَلَيْكُمْ فَكُنتُمْ عَلَىٰٓ أَعْقَٰبِكُمْ تَنكِصُونَ", transliteration: "Qad kanat ayatee tutla AAalaykum fakuntum AAala aAAqabikum tankisoona", transliterationB: "Qad kaanat Aayaatee tutlaa 'alaikum fakuntum 'alaaa a'qaabikum tankisoon", english: "My Signs used to be rehearsed to you, but ye used to turn back on your heels", romanUrdu: "Meri aayat sunayi jati thi to tum (Rasool ki aawaz sunte hi) ultay paon bhaag nikalte thay" },
    { number: 67, arabic: "مُسْتَكْبِرِينَ بِهِۦ سَٰمِرًۭا تَهْجُرُونَ", transliteration: "Mustakbireena bihi samiran tahjuroona", transliterationB: "Mustakbireena bihee saamiran tahjuroon", english: "In arrogance: talking nonsense about the (Qur'an), like one telling fables by night", romanUrdu: "Apne ghamand mein usko khatir hi mein na latey thay,apne chaoupalon (meeting places) mein unpar baatein chaant-te (ridiculed him) aur bakwas kiya karte thay" },
    { number: 68, arabic: "أَفَلَمْ يَدَّبَّرُوا۟ ٱلْقَوْلَ أَمْ جَآءَهُم مَّا لَمْ يَأْتِ ءَابَآءَهُمُ ٱلْأَوَّلِينَ", transliteration: "Afalam yaddabbaroo alqawla am jaahum ma lam yati abaahumu alawwaleena", transliterationB: "Afalam yaddabbarrul qawla am jaaa'ahum maa lam yaati aabaaa'ahumul awwaleen", english: "Do they not ponder over the Word (of Allah), or has anything (new) come to them that did not come to their fathers of old", romanUrdu: "To kya in logon ne kabhi is kalaam par gaur nahin kiya? Ya woh koi aisi baat laya hai jo kabhi inke aslaaf (forefathers) ke paas na aayi thi" },
    { number: 69, arabic: "أَمْ لَمْ يَعْرِفُوا۟ رَسُولَهُمْ فَهُمْ لَهُۥ مُنكِرُونَ", transliteration: "Am lam yaAArifoo rasoolahum fahum lahu munkiroona", transliterationB: "Am lam ya'rifoo Rasoolahum fahum lahoo munkiroon", english: "Or do they not recognise their Messenger, that they deny him", romanUrdu: "Ya yeh apne Rasool se kabhi ke waqif na thay ke (anjaana aadmi honay ke baais) ussey bidakte hain" },
    { number: 70, arabic: "أَمْ يَقُولُونَ بِهِۦ جِنَّةٌۢ ۚ بَلْ جَآءَهُم بِٱلْحَقِّ وَأَكْثَرُهُمْ لِلْحَقِّ كَٰرِهُونَ", transliteration: "Am yaqooloona bihi jinnatun bal jaahum bialhaqqi waaktharuhum lilhaqqi karihoona", transliterationB: "Am yaqooloona bihee jinnnah; bal jaaa'ahum bilhaqqi wa aksaruhum lil haqqi kaarihoon", english: "Or do they say, \"He is possessed\"? Nay, he has brought them the Truth, but most of them hate the Truth", romanUrdu: "Ya ye is baat ke qayal hain ke woh majnoon [possessed (by a jinn)] hai? Nahin, balke woh haqq laya hai aur haqq hi inki aksariyat (most) ko nagawar hai" },
    { number: 71, arabic: "وَلَوِ ٱتَّبَعَ ٱلْحَقُّ أَهْوَآءَهُمْ لَفَسَدَتِ ٱلسَّمَٰوَٰتُ وَٱلْأَرْضُ وَمَن فِيهِنَّ ۚ بَلْ أَتَيْنَٰهُم بِذِكْرِهِمْ فَهُمْ عَن ذِكْرِهِم مُّعْرِضُونَ", transliteration: "Walawi ittabaAAa alhaqqu ahwaahum lafasadati alssamawatu waalardu waman feehinna bal ataynahum bithikrihim fahum AAan thikrihim muAAridoona", transliterationB: "Wa lawit taba'al haqqu ahwaaa'ahum lafasadatis samaawaatu wal ardu wa man feehinnn; bal atainaahum bizikrihim fahum 'an zikrihim mu'ridon", english: "If the Truth had been in accord with their desires, truly the heavens and the earth, and all beings therein would have been in confusion and corruption! Nay, We have sent them their admonition, but they turn away from their admonition", romanUrdu: "Aur haqq agar kahin inki khwaishaat ke peechey chalta to zameen aur aasman aur inki saari aabaadi ka nizam darham barham ho jata. Nahin, balke hum unka apna hi zikar unke paas laaye hain aur woh apne zikr se mooh moad rahey hain" },
    { number: 72, arabic: "أَمْ تَسْـَٔلُهُمْ خَرْجًۭا فَخَرَاجُ رَبِّكَ خَيْرٌۭ ۖ وَهُوَ خَيْرُ ٱلرَّٰزِقِينَ", transliteration: "Am tasaluhum kharjan fakharaju rabbika khayrun wahuwa khayru alrraziqeena", transliterationB: "Am tas'aluhum kharjan fakharaaju Rabbika khairunw wa Huwa khairur raaziqeen", english: "Or is it that thou askest them for some recompense? But the recompense of thy Lord is best: He is the Best of those who give sustenance", romanUrdu: "Kya tu insey kuch maang raha hai? Tere liye tere Rubb ka diya hi behtar hai aur woh behtareen raziq hai" },
    { number: 73, arabic: "وَإِنَّكَ لَتَدْعُوهُمْ إِلَىٰ صِرَٰطٍۢ مُّسْتَقِيمٍۢ", transliteration: "Wainnaka latadAAoohum ila siratin mustaqeemin", transliterationB: "Wa innaka latad'oohum ilaa Siraatim Mustaqeem", english: "But verily thou callest them to the Straight Way", romanUrdu: "Tu to unko seedhey raaste ki taraf bula raha hai" },
    { number: 74, arabic: "وَإِنَّ ٱلَّذِينَ لَا يُؤْمِنُونَ بِٱلْءَاخِرَةِ عَنِ ٱلصِّرَٰطِ لَنَٰكِبُونَ", transliteration: "Wainna allatheena la yuminoona bialakhirati AAani alssirati lanakiboona", transliterationB: "Wa innnal lazeena laa yu'minoona bil Aakhirati 'anis siraati lanaakiboon", english: "And verily those who believe not in the Hereafter are deviating from that Way", romanUrdu: "Magar jo log aakhirat ko nahin maante woh raah e raast se hat kar chalna chahte hain" },
    { number: 75, arabic: "۞ وَلَوْ رَحِمْنَٰهُمْ وَكَشَفْنَا مَا بِهِم مِّن ضُرٍّۢ لَّلَجُّوا۟ فِى طُغْيَٰنِهِمْ يَعْمَهُونَ", transliteration: "Walaw rahimnahum wakashafna ma bihim min durrin lalajjoo fee tughyanihim yaAAmahoona", transliterationB: "Wa law rahimnaahum wa kashafnaa maa bihim min durril lalajjoo fee tughyaanihim ya'mahoon", english: "If We had mercy on them and removed the distress which is on them, they would obstinately persist in their transgression, wandering in distraction to and fro", romanUrdu: "Agar hum inpar reham karein aur woh takleef jis mein aaj kal yeh mubtila hain door kardein to yeh apni sarkashi mein bilkul hi behak jayenge" },
    { number: 76, arabic: "وَلَقَدْ أَخَذْنَٰهُم بِٱلْعَذَابِ فَمَا ٱسْتَكَانُوا۟ لِرَبِّهِمْ وَمَا يَتَضَرَّعُونَ", transliteration: "Walaqad akhathnahum bialAAathabi fama istakanoo lirabbihim wama yatadarraAAoona", transliterationB: "Wa laqad akhaznaahum bil'azaabi famastakaanoo li Rabbihim wa maa yatadarra'oon", english: "We inflicted Punishment on them, but they humbled not themselves to their Lord, nor do they submissively entreat (Him)", romanUrdu: "Inka haal to yeh hai ke humne unhein takleef mein mubtila kiya, phir bhi yeh apne Rubb ke aagey na jhuke aur na aajizi (humble)ikhtiyar karte hain" },
    { number: 77, arabic: "حَتَّىٰٓ إِذَا فَتَحْنَا عَلَيْهِم بَابًۭا ذَا عَذَابٍۢ شَدِيدٍ إِذَا هُمْ فِيهِ مُبْلِسُونَ", transliteration: "Hatta itha fatahna AAalayhim baban tha AAathabin shadeedin itha hum feehi mublisoona", transliterationB: "Hattaaa izaa fatahnaa 'alaihim baaban zaa 'azaabin shadeedin izaa hum feehi mublisoon", english: "Until We open on them a gate leading to a severe Punishment: then Lo! they will be plunged in despair therein", romanUrdu: "Albatta jab naubat yahan tak pahunch jayegi ke hum inpar sakht azaab ka darwaza khol denge to yakayak tum dekhoge ke us halat mein ye har khair se mayous hain" },
    { number: 78, arabic: "وَهُوَ ٱلَّذِىٓ أَنشَأَ لَكُمُ ٱلسَّمْعَ وَٱلْأَبْصَٰرَ وَٱلْأَفْـِٔدَةَ ۚ قَلِيلًۭا مَّا تَشْكُرُونَ", transliteration: "Wahuwa allathee anshaa lakumu alssamAAa waalabsara waalafidata qaleelan ma tashkuroona", transliterationB: "Wa Huwal lazeee ansha a-lakumus sam'a wal absaara wal af'idah; qaleelam maa tashkuroon", english: "It is He Who has created for you (the faculties of) hearing, sight, feeling and understanding: little thanks it is ye give", romanUrdu: "Woh Allah hi to hai jisne tumhein sunney aur dekhne ki quwwatein di aur sochne ko dil diye , magar tum log kam hi shukarguzar hotey ho" },
    { number: 79, arabic: "وَهُوَ ٱلَّذِى ذَرَأَكُمْ فِى ٱلْأَرْضِ وَإِلَيْهِ تُحْشَرُونَ", transliteration: "Wahuwa allathee tharaakum fee alardi wailayhi tuhsharoona", transliterationB: "Wa Huwal lazee zara akum fil ardi wa ilaihi tuhsharoon", english: "And He has multiplied you through the earth, and to Him shall ye be gathered back", romanUrdu: "Wahi hai jisne tumhein zameen mein phaylaya, aur usi ki taraf tum sametay jaogey" },
    { number: 80, arabic: "وَهُوَ ٱلَّذِى يُحْىِۦ وَيُمِيتُ وَلَهُ ٱخْتِلَٰفُ ٱلَّيْلِ وَٱلنَّهَارِ ۚ أَفَلَا تَعْقِلُونَ", transliteration: "Wahuwa allathee yuhyee wayumeetu walahu ikhtilafu allayli waalnnahari afala taAAqiloona", transliterationB: "Wa Huwal lazee yuhyee wa yumeetu wa lahukh tilaaful laili wannahaar; afalaa ta'qiloon", english: "It is He Who gives life and death, and to Him (is due) the alternation of Night and Day: will ye not then understand", romanUrdu: "Wahi zindagi bakashta hai aur wahi maut deta hai, gardish e layl (raat) o nahar (din) usi ke qabze qudrat mein hai. Kya tumhari samajh mein yeh baat nahin aati" },
    { number: 81, arabic: "بَلْ قَالُوا۟ مِثْلَ مَا قَالَ ٱلْأَوَّلُونَ", transliteration: "Bal qaloo mithla ma qala alawwaloona", transliterationB: "Bal qaaloo misla maa qaalal awwaloon", english: "On the contrary they say things similar to what the ancients said", romanUrdu: "Magar yeh log wahi kuch kehte hain jo unke peshraw (forefathers) keh chuke hain" },
    { number: 82, arabic: "قَالُوٓا۟ أَءِذَا مِتْنَا وَكُنَّا تُرَابًۭا وَعِظَٰمًا أَءِنَّا لَمَبْعُوثُونَ", transliteration: "Qaloo aitha mitna wakunna turaban waAAithaman ainna lamabAAoothoona", transliterationB: "Qaalooo 'a-izaa mitnaa wa kunnaa turaabanw wa 'izaaman 'a-innaa lamab 'oosoon", english: "They say: \"What! when we die and become dust and bones, could we really be raised up again", romanUrdu: "Yeh kehte hain “kya jab hum marr kar mitti ho jayenge aur haddiyon ka panjar ban kar reh jayenge to humko phir zinda karke uthaya jayega" },
    { number: 83, arabic: "لَقَدْ وُعِدْنَا نَحْنُ وَءَابَآؤُنَا هَٰذَا مِن قَبْلُ إِنْ هَٰذَآ إِلَّآ أَسَٰطِيرُ ٱلْأَوَّلِينَ", transliteration: "Laqad wuAAidna nahnu waabaona hatha min qablu in hatha illa asateeru alawwaleena", transliterationB: "Laqad wu'idnaa nahnu wa aabaaa'unaa haazaa min qablu in haazaaa illaaa asaateerul awwaleen", english: "Such things have been promised to us and to our fathers before! they are nothing but tales of the ancients", romanUrdu: "Humne bhi yeh wadey bahut sunay hain aur humse pehle hamare baap dada bhi suntey rahey hain. Yeh mehaz afasana haye pareena hain(ancient tales)”" },
    { number: 84, arabic: "قُل لِّمَنِ ٱلْأَرْضُ وَمَن فِيهَآ إِن كُنتُمْ تَعْلَمُونَ", transliteration: "Qul limani alardu waman feeha in kuntum taAAlamoona", transliterationB: "Qul limanil ardu wa man feehaaa in kuntum ta'lamoon", english: "Say: \"To whom belong the earth and all beings therein? (say) if ye know", romanUrdu: "Insey kaho, batao agar tum jaante ho, ke yeh zameen aur iski saari aabaadi kiski hai" },
    { number: 85, arabic: "سَيَقُولُونَ لِلَّهِ ۚ قُلْ أَفَلَا تَذَكَّرُونَ", transliteration: "Sayaqooloona lillahi qul afala tathakkaroona", transliterationB: "Sa-yaqooloona lillaah; qul afalaa tazakkkaroon", english: "They will say, \"To Allah!\" say: \"Yet will ye not receive admonition", romanUrdu: "Yeh zaroor kahenge ke Allah ki, kaho phir tum hosh mein kyun nahin aatey" },
    { number: 86, arabic: "قُلْ مَن رَّبُّ ٱلسَّمَٰوَٰتِ ٱلسَّبْعِ وَرَبُّ ٱلْعَرْشِ ٱلْعَظِيمِ", transliteration: "Qul man rabbu alssamawati alssabAAi warabbu alAAarshi alAAatheemi", transliterationB: "Qul mar Rabbus samaawaatis sab'i wa Rabbul 'Arshil 'Azeem", english: "Say: \"Who is the Lord of the seven heavens, and the Lord of the Throne (of Glory) Supreme", romanUrdu: "Insey pucho, saato (seven) aasmaano aur arsh-e-azeem ka maalik kaun hai" },
    { number: 87, arabic: "سَيَقُولُونَ لِلَّهِ ۚ قُلْ أَفَلَا تَتَّقُونَ", transliteration: "Sayaqooloona lillahi qul afala tattaqoona", transliterationB: "Sa yaqooloona lillaah; qul afalaa tattaqoon", english: "They will say, \"(They belong) to Allah.\" Say: \"Will ye not then be filled with awe", romanUrdu: "Yeh zaroor kahenge Allah, kaho phir tum darte kyun nahin" },
    { number: 88, arabic: "قُلْ مَنۢ بِيَدِهِۦ مَلَكُوتُ كُلِّ شَىْءٍۢ وَهُوَ يُجِيرُ وَلَا يُجَارُ عَلَيْهِ إِن كُنتُمْ تَعْلَمُونَ", transliteration: "Qul man biyadihi malakootu kulli shayin wahuwa yujeeru wala yujaru AAalayhi in kuntum taAAlamoona", transliterationB: "Qul mam bi yadihee malakootu kulli shai'inw wa Huwa yujeeru wa laa yujaaru 'alaihi in kuntum ta'lamoon", english: "Say: \"Who is it in whose hands is the governance of all things,- who protects (all), but is not protected (of any)? (say) if ye know", romanUrdu: "Insey kaho, batao agar tum jaante ho ke har cheez par iqtedaar kiska hai? Aur kaun hai woh jo panaah deta hai aur uske muqable mein koi panaah nahin de sakta" },
    { number: 89, arabic: "سَيَقُولُونَ لِلَّهِ ۚ قُلْ فَأَنَّىٰ تُسْحَرُونَ", transliteration: "Sayaqooloona lillahi qul faanna tusharoona", transliterationB: "Sa yaqooloona lillaah; qul fa annaa tus haroon", english: "They will say, \"(It belongs) to Allah.\" Say: \"Then how are ye deluded", romanUrdu: "Yeh zaroor kahenge ke yeh baat to Allah hi keliye hai. Kaho, phir kahan se tumko dhoka lagta hai" },
    { number: 90, arabic: "بَلْ أَتَيْنَٰهُم بِٱلْحَقِّ وَإِنَّهُمْ لَكَٰذِبُونَ", transliteration: "Bal ataynahum bialhaqqi wainnahum lakathiboona", transliterationB: "Bal atainaahum bil haqqi wa innahum lakaaziboon", english: "We have sent them the Truth: but they indeed practise falsehood", romanUrdu: "Jo amr e haqq hai woh hum inke saamne le aaye hain, aur koi shakk nahin ke yeh log jhotey hain" },
    { number: 91, arabic: "مَا ٱتَّخَذَ ٱللَّهُ مِن وَلَدٍۢ وَمَا كَانَ مَعَهُۥ مِنْ إِلَٰهٍ ۚ إِذًۭا لَّذَهَبَ كُلُّ إِلَٰهٍۭ بِمَا خَلَقَ وَلَعَلَا بَعْضُهُمْ عَلَىٰ بَعْضٍۢ ۚ سُبْحَٰنَ ٱللَّهِ عَمَّا يَصِفُونَ", transliteration: "Ma ittakhatha Allahu min waladin wama kana maAAahu min ilahin ithan lathahaba kullu ilahin bima khalaqa walaAAala baAAduhum AAala baAAdin subhana Allahi AAamma yasifoona", transliterationB: "Mat takhazal laahu minw waladinw wa maa kaana ma'ahoo min ilaah; izal lazahaba kullu ilaahim bimaa khalaqa wa la'alaa ba'duhum 'alaa ba'd; Subhaannal laahi 'ammaa yasifoon", english: "No son did Allah beget, nor is there any god along with Him: (if there were many gods), behold, each god would have taken away what he had created, and some would have lorded it over others! Glory to Allah! (He is free) from the (sort of) things they attribute to Him", romanUrdu: "Allah ne kisi ko apni aulaad nahin banaya hai aur koi dusra khuda uske saath nahin hai. Agar aisa hota to har khuda apni khalq ko lekar alag ho jaata, aur phir woh ek dusre par chadh daudte.Paak hai Allah un baaton se jo yeh log banate hain" },
    { number: 92, arabic: "عَٰلِمِ ٱلْغَيْبِ وَٱلشَّهَٰدَةِ فَتَعَٰلَىٰ عَمَّا يُشْرِكُونَ", transliteration: "AAalimi alghaybi waalshshahadati fataAAala AAamma yushrikoona", transliterationB: "Aalimil Ghaibi wash shahhaadati fata'aalaa 'ammaa yushrikoon", english: "He knows what is hidden and what is open: too high is He for the partners they attribute to Him", romanUrdu: "Khule aur chupe ka jaanne wala, woh baalatar hai us shirk se jo yeh log tajweez kar rahey hain" },
    { number: 93, arabic: "قُل رَّبِّ إِمَّا تُرِيَنِّى مَا يُوعَدُونَ", transliteration: "Qul rabbi imma turiyannee ma yooAAadoona", transliterationB: "Qur Rabbi immmaa turiyannee maa yoo'adoon", english: "Say: \"O my Lord! if Thou wilt show me (in my lifetime) that which they are warned against", romanUrdu: "(Aey Muhammad) dua karo ke “parwardigar, jis azaab ki inko dhamki di jaa rahi hai woh agar meri maujoodgi mein tu laye" },
    { number: 94, arabic: "رَبِّ فَلَا تَجْعَلْنِى فِى ٱلْقَوْمِ ٱلظَّٰلِمِينَ", transliteration: "Rabbi fala tajAAalnee fee alqawmi alththalimeena", transliterationB: "Rabbi falaa taj'alnee fil qawmiz zaalimeen", english: "Then, O my Lord! put me not amongst the people who do wrong", romanUrdu: "To aey mere Rubb, mujhey in zaalim logon mein shamil na kijiyo”" },
    { number: 95, arabic: "وَإِنَّا عَلَىٰٓ أَن نُّرِيَكَ مَا نَعِدُهُمْ لَقَٰدِرُونَ", transliteration: "Wainna AAala an nuriyaka ma naAAiduhum laqadiroona", transliterationB: "Wa innaa 'alaaa an nuriyaka maa na'iduhum laqaadiroon", english: "And We are certainly able to show thee (in fulfilment) that against which they are warned", romanUrdu: "Aur haqeeqat yeh hai ke hum tumhari aankhon ke saamne hi woh cheez le aane ki poori qudrat rakhte hain jiski dhamki hum unhein de rahey hain" },
    { number: 96, arabic: "ٱدْفَعْ بِٱلَّتِى هِىَ أَحْسَنُ ٱلسَّيِّئَةَ ۚ نَحْنُ أَعْلَمُ بِمَا يَصِفُونَ", transliteration: "IdfaAA biallatee hiya ahsanu alssayyiata nahnu aAAlamu bima yasifoona", transliterationB: "Idfa' billate hiya ahsanus saiyi'ah; nahnu a'lamu bimaa yasifoon", english: "Repel evil with that which is best: We are well acquainted with the things they say", romanUrdu: "(Aey Nabi), burayi ko is tareeqe se dafa karo jo behtareen ho jo kuch baatein woh tumpar banate hain woh humein khoob maloom hai" },
    { number: 97, arabic: "وَقُل رَّبِّ أَعُوذُ بِكَ مِنْ هَمَزَٰتِ ٱلشَّيَٰطِينِ", transliteration: "Waqul rabbi aAAoothu bika min hamazati alshshayateeni", transliterationB: "Wa qur Rabbi a'oozu bika min hamazaatish Shayaateen", english: "And say \"O my Lord! I seek refuge with Thee from the suggestions of the Evil Ones", romanUrdu: "Aur dua karo ke “parwardigar, main shayateen ki uksahaton(waswason) se teri panaah maangta hoon" },
    { number: 98, arabic: "وَأَعُوذُ بِكَ رَبِّ أَن يَحْضُرُونِ", transliteration: "WaaAAoothu bika rabbi an yahdurooni", transliterationB: "Wa a'oozu bika Rabbi ai-yahduroon", english: "And I seek refuge with Thee O my Lord! lest they should come near me", romanUrdu: "Balke aey mere Rubb, main to issey bhi teri panaah maanga hoon ke woh mere paas aayein”" },
    { number: 99, arabic: "حَتَّىٰٓ إِذَا جَآءَ أَحَدَهُمُ ٱلْمَوْتُ قَالَ رَبِّ ٱرْجِعُونِ", transliteration: "Hatta itha jaa ahadahumu almawtu qala rabbi irjiAAooni", transliterationB: "Hattaaa izaa jaaa'a ahada humul mawtu qaala Rabbir ji'oon", english: "(In Falsehood will they be) Until, when death comes to one of them, he says: \"O my Lord! send me back (to life)", romanUrdu: "(yeh log apni karni se baaz na aayenge) yahan tak ke jab in mein se kisi ko maut aa jayegi to kehna shuru kardega ke “Aey mere Rubb, mujhey usi duniya mein wapas bhej dijiye jisey main chodh aaya hoon" },
    { number: 100, arabic: "لَعَلِّىٓ أَعْمَلُ صَٰلِحًۭا فِيمَا تَرَكْتُ ۚ كَلَّآ ۚ إِنَّهَا كَلِمَةٌ هُوَ قَآئِلُهَا ۖ وَمِن وَرَآئِهِم بَرْزَخٌ إِلَىٰ يَوْمِ يُبْعَثُونَ", transliteration: "LaAAallee aAAmalu salihan feema taraktu kalla innaha kalimatun huwa qailuha wamin waraihim barzakhun ila yawmi yubAAathoona", transliterationB: "La'alleee a'malu saalihan feemaa taraktu kallaa; innahaa kalimatun huwa qaaa'iluhaa wa minw waraaa'him barzakhun ilaa Yawmi yub'asoon", english: "In order that I may work righteousness in the things I neglected.\" - \"By no means! It is but a word he says.\"- Before them is a Partition till the Day they are raised up", romanUrdu: "Umeed hai ke ab main neik amal karunga”. Hargiz nahin, yeh to bas ek baat hai jo woh bakk raha hai. Ab in sab (marne waalon) ke peechey ek barzakh (barrier) hayal hai dusri zindagi ke din tak" },
    { number: 101, arabic: "فَإِذَا نُفِخَ فِى ٱلصُّورِ فَلَآ أَنسَابَ بَيْنَهُمْ يَوْمَئِذٍۢ وَلَا يَتَسَآءَلُونَ", transliteration: "Faitha nufikha fee alssoori fala ansaba baynahum yawmaithin wala yatasaaloona", transliterationB: "Fa izaa nufikha fis Soori falaaa ansaaba bainahum yawma'izinw wa laa yatasaaa'aloon", english: "Then when the Trumpet is blown, there will be no more relationships between them that Day, nor will one ask after another", romanUrdu: "Phir junhi ke Sur (trumphet) phoonk diya gaya, unke darmiyan phir koi rishta na rahega aur na woh ek dusre ko puchenge" },
    { number: 102, arabic: "فَمَن ثَقُلَتْ مَوَٰزِينُهُۥ فَأُو۟لَٰٓئِكَ هُمُ ٱلْمُفْلِحُونَ", transliteration: "Faman thaqulat mawazeenuhu faolaika humu almuflihoona", transliterationB: "Faman saqulat mawaazee nuhoo fa ulaaa'ika humul muflihoon", english: "Then those whose balance (of good deeds) is heavy,- they will attain salvation", romanUrdu: "Us waqt jinke padle (scales) bhari hongey wahi falaah payenge" },
    { number: 103, arabic: "وَمَنْ خَفَّتْ مَوَٰزِينُهُۥ فَأُو۟لَٰٓئِكَ ٱلَّذِينَ خَسِرُوٓا۟ أَنفُسَهُمْ فِى جَهَنَّمَ خَٰلِدُونَ", transliteration: "Waman khaffat mawazeenuhu faolaika allatheena khasiroo anfusahum fee jahannama khalidoona", transliterationB: "Wa man khaffat mawaa zeenuhoo fa ulaaa'ikal lazeena khasiroon anfusahum fee Jahannnama khaalidoon", english: "But those whose balance is light, will be those who have lost their souls, in Hell will they abide", romanUrdu: "Aur jinke padle (scales) halke honge wahi log hongey jinhon ne apne aap ko ghatay mein daal liya. Woh jahannum mein hamesha rahenge" },
    { number: 104, arabic: "تَلْفَحُ وُجُوهَهُمُ ٱلنَّارُ وَهُمْ فِيهَا كَٰلِحُونَ", transliteration: "Talfahu wujoohahumu alnnaru wahum feeha kalihoona", transliterationB: "Talfahu wujoohahumun Naaru wa hum feehaa kaalihood", english: "The Fire will burn their faces, and they will therein grin, with their lips displaced", romanUrdu: "Aag unke chehron ki khaal chaat jayegi aur unke jabde (jaws) bahar nikal aayenge" },
    { number: 105, arabic: "أَلَمْ تَكُنْ ءَايَٰتِى تُتْلَىٰ عَلَيْكُمْ فَكُنتُم بِهَا تُكَذِّبُونَ", transliteration: "Alam takun ayatee tutla AAalaykum fakuntum biha tukaththiboona", transliterationB: "Alam takun Aayaatee tutlaa 'alaikum fakuntum bihaa tukazziboon", english: "Were not My Signs rehearsed to you, and ye did but treat them as falsehood", romanUrdu: "“kya tum wahi log nahin ho ke meri aayat tumhein sunayi jati thi to tum unhein jhutlate thay?”" },
    { number: 106, arabic: "قَالُوا۟ رَبَّنَا غَلَبَتْ عَلَيْنَا شِقْوَتُنَا وَكُنَّا قَوْمًۭا ضَآلِّينَ", transliteration: "Qaloo rabbana ghalabat AAalayna shiqwatuna wakunna qawman dalleena", transliterationB: "Qaaloo Rabbanaa ghalabat 'alainaa shiqwatunaa wa kunnaa qawman daaalleen", english: "They will say: \"our Lord! Our misfortune overwhelmed us, and we became a people astray", romanUrdu: "Woh kahenge “aey hamare Rubb, hamari badbakhti hum par chaa gayi thi, hum waqayi gumraah log thay" },
    { number: 107, arabic: "رَبَّنَآ أَخْرِجْنَا مِنْهَا فَإِنْ عُدْنَا فَإِنَّا ظَٰلِمُونَ", transliteration: "Rabbana akhrijna minha fain AAudna fainna thalimoona", transliterationB: "Rabbanaa akhrijnaa minhaa fa in 'udnaa fa innaa zaalimoon", english: "Our Lord! bring us out of this: if ever we return (to Evil), then shall we be wrong-doers indeed", romanUrdu: "Aey parwardigar, ab humein yahan se nikaal de phir hum aisa kasoor karein to zaalim hongey”" },
    { number: 108, arabic: "قَالَ ٱخْسَـُٔوا۟ فِيهَا وَلَا تُكَلِّمُونِ", transliteration: "Qala ikhsaoo feeha wala tukallimooni", transliterationB: "Qaalakh sa'oo feehaa wa laa tukallimoon", english: "He will say: \"Be ye driven into it (with ignominy)! And speak ye not to Me", romanUrdu: "Allah taala jawab dega “ door ho mere saamne se, padey raho isi mein aur mujhse baat na karo" },
    { number: 109, arabic: "إِنَّهُۥ كَانَ فَرِيقٌۭ مِّنْ عِبَادِى يَقُولُونَ رَبَّنَآ ءَامَنَّا فَٱغْفِرْ لَنَا وَٱرْحَمْنَا وَأَنتَ خَيْرُ ٱلرَّٰحِمِينَ", transliteration: "Innahu kana fareequn min AAibadee yaqooloona rabbana amanna faighfir lana wairhamna waanta khayru alrrahimeena", transliterationB: "Innahoo kaana fareequm min 'ibaadee yaqooloona Rabbanaaa aamannaa faghfir lanaa warhamnaa wa Anta khairur raahimeen", english: "A part of My servants there was, who used to pray 'our Lord! we believe; then do Thou forgive us, and have mercy upon us: For Thou art the Best of those who show mercy", romanUrdu: "Tum wahi log to ho ke mere kuch banday jab kehte thay ke aye hamare parwardigar, hum iman laye, humein maaf karde, humpar reham kar, tu sab raheemon se accha raheem hai" },
    { number: 110, arabic: "فَٱتَّخَذْتُمُوهُمْ سِخْرِيًّا حَتَّىٰٓ أَنسَوْكُمْ ذِكْرِى وَكُنتُم مِّنْهُمْ تَضْحَكُونَ", transliteration: "Faittakhathtumoohum sikhriyyan hatta ansawkum thikree wakuntum minhum tadhakoona", transliterationB: "Fattakhaztumoohum sikhriyyan hattaaa ansawkum zikree wa kuntum minhum tadhakoon", english: "But ye treated them with ridicule, so much so that (ridicule of) them made you forget My Message while ye were laughing at them", romanUrdu: "To tumne unka mazaaq bana liye, yahan tak ke unki zidd ne tumhein yeh bhi bhula diya ke main bhi koi hoon, aur tum unpar haste rahey" },
    { number: 111, arabic: "إِنِّى جَزَيْتُهُمُ ٱلْيَوْمَ بِمَا صَبَرُوٓا۟ أَنَّهُمْ هُمُ ٱلْفَآئِزُونَ", transliteration: "Innee jazaytuhumu alyawma bima sabaroo annahum humu alfaizoona", transliterationB: "Inee jazaituhumul Yawma bimaa sabarooo annahum humul faaa'izoon", english: "I have rewarded them this Day for their patience and constancy: they are indeed the ones that have achieved Bliss", romanUrdu: "Aaj unke us sabr ka maine yeh phal diya hai ke wahi kamiyaab hain”" },
    { number: 112, arabic: "قَٰلَ كَمْ لَبِثْتُمْ فِى ٱلْأَرْضِ عَدَدَ سِنِينَ", transliteration: "Qala kam labithtum fee alardi AAadada sineena", transliterationB: "Qaala kam labistum fil ardi 'adada sineen", english: "He will say: \"What number of years did ye stay on earth", romanUrdu: "Phir Allah taala unse puchega “batao,zameen mein tum kitne saal rahey?”" },
    { number: 113, arabic: "قَالُوا۟ لَبِثْنَا يَوْمًا أَوْ بَعْضَ يَوْمٍۢ فَسْـَٔلِ ٱلْعَآدِّينَ", transliteration: "Qaloo labithna yawman aw baAAda yawmin faisali alAAaddeena", transliterationB: "Qaaloo labisnaa yawman aw ba'da yawmin fas'alil 'aaaddeen", english: "They will say: \"We stayed a day or part of a day: but ask those who keep account", romanUrdu: "Woh kahenge “ ek din ya din ka bhi kuch hissa hum wahan thehre hain, shumaar karne walon se pooch lijiye”" },
    { number: 114, arabic: "قَٰلَ إِن لَّبِثْتُمْ إِلَّا قَلِيلًۭا ۖ لَّوْ أَنَّكُمْ كُنتُمْ تَعْلَمُونَ", transliteration: "Qala in labithtum illa qaleelan law annakum kuntum taAAlamoona", transliterationB: "Qaala il labistum illaa qaleelal law annakum kuntum ta'lamoon", english: "He will say: \"Ye stayed not but a little,- if ye had only known", romanUrdu: "Irshad hoga “ thodi hi dair thehre ho na, kaash tumne yeh us waqt jana hota" },
    { number: 115, arabic: "أَفَحَسِبْتُمْ أَنَّمَا خَلَقْنَٰكُمْ عَبَثًۭا وَأَنَّكُمْ إِلَيْنَا لَا تُرْجَعُونَ", transliteration: "Afahasibtum annama khalaqnakum AAabathan waannakum ilayna la turjaAAoona", transliterationB: "Afahsibtum annamaa khalaqnaakum 'abasanw wa annakum ilainaa laa turja'oon", english: "Did ye then think that We had created you in jest, and that ye would not be brought back to Us (for account)", romanUrdu: "Kya tumne yeh samajh rakkha tha ke humne tumhein fizul(bekar) hi paida kiya hai aur tumhein hamari taraf kabhi palatna hi nahin hai?”" },
    { number: 116, arabic: "فَتَعَٰلَى ٱللَّهُ ٱلْمَلِكُ ٱلْحَقُّ ۖ لَآ إِلَٰهَ إِلَّا هُوَ رَبُّ ٱلْعَرْشِ ٱلْكَرِيمِ", transliteration: "FataAAala Allahu almaliku alhaqqu la ilaha illa huwa rabbu alAAarshi alkareemi", transliterationB: "Fata'aalal laahul Malikul Haqq; laaa ilaaha illaa Huwa Rabbul 'Arshil Kareem", english: "Therefore exalted be Allah, the King, the Reality: there is no god but He, the Lord of the Throne of Honour", romanUrdu: "Pas baala o bartar hai Allah , baadshah e haqiqi, koi khuda uske siwa nahin, maalik hai arsh e buzurg ka" },
    { number: 117, arabic: "وَمَن يَدْعُ مَعَ ٱللَّهِ إِلَٰهًا ءَاخَرَ لَا بُرْهَٰنَ لَهُۥ بِهِۦ فَإِنَّمَا حِسَابُهُۥ عِندَ رَبِّهِۦٓ ۚ إِنَّهُۥ لَا يُفْلِحُ ٱلْكَٰفِرُونَ", transliteration: "Waman yadAAu maAAa Allahi ilahan akhara la burhana lahu bihi fainnama hisabuhu AAinda rabbihi innahu la yuflihu alkafiroona", transliterationB: "Wa mai yad'u ma'allaahi ilaahan aakhara laa burhaana lahoo bihee fa innnamaa hisaabuhoo 'inda Rabbih; innahoo laa yuflihul kaafiroon", english: "If anyone invokes, besides Allah, Any other god, he has no authority therefor; and his reckoning will be only with his Lord! and verily the Unbelievers will fail to win through", romanUrdu: "Aur jo koi Allah ke saath kisi aur maabood ko pukare, jiske liye uske paas koi daleel nahin, to uska hisaab uske Rubb ke paas hai. Aisey kafir kabhi falaah nahin paa sakte" },
    { number: 118, arabic: "وَقُل رَّبِّ ٱغْفِرْ وَٱرْحَمْ وَأَنتَ خَيْرُ ٱلرَّٰحِمِينَ", transliteration: "Waqul rabbi ighfir wairham waanta khayru alrrahimeena", transliterationB: "Wa qur Rabbigh fir warham wa Anta khairur raahimeen", english: "So say: \"O my Lord! grant Thou forgiveness and mercy for Thou art the Best of those who show mercy", romanUrdu: "(Aey Muhammad) kaho, “Mere Rubb darguzar farma, aur reham kar, aur tu sab raheemon se accha raheem hai”" }
  ]
};
